import{_ as a,o as t,c as e,a0 as r}from"./chunks/framework.BjpW4enL.js";const _=JSON.parse('{"title":"Draft: Migração T4 Nativo (Rust Coordinator)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_reports/RUST_T4_MIGRATION_SPEC.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_reports/RUST_T4_MIGRATION_SPEC.md","lastUpdated":1783623176000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_reports/RUST_T4_MIGRATION_SPEC.md"};function s(n,o,l,c,d,u){return t(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="draft-migracao-t4-nativo-rust-coordinator" tabindex="-1">Draft: Migração T4 Nativo (Rust Coordinator) <a class="header-anchor" href="#draft-migracao-t4-nativo-rust-coordinator" aria-label="Permalink to &quot;Draft: Migração T4 Nativo (Rust Coordinator)&quot;">​</a></h1><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Transformar o <code>nexus_context.py</code> (Spec Executável) em endpoints nativos no Coordinator para performance e integração total.</p><h2 id="novos-endpoints-propostos" tabindex="-1">Novos Endpoints Propostos <a class="header-anchor" href="#novos-endpoints-propostos" aria-label="Permalink to &quot;Novos Endpoints Propostos&quot;">​</a></h2><h3 id="_1-post-query-topological" tabindex="-1">1. <code>POST /query/topological</code> <a class="header-anchor" href="#_1-post-query-topological" aria-label="Permalink to &quot;1. `POST /query/topological`&quot;">​</a></h3><ul><li><strong>Input</strong>: <code>{ &quot;query&quot;: string, &quot;limit&quot;: int, &quot;radius&quot;: int }</code></li><li><strong>Logic</strong>: <ol><li>Chamada interna ao Ollama (Embeddings).</li><li>Chamada interna ao Qdrant (T3 Search).</li><li>Execução do algoritmo PPR (Personalized PageRank) em Rust usando <code>sqlx</code>.</li><li>Reidratação dos conteúdos (T2).</li></ol></li><li><strong>Return</strong>: Lista de Abstrações L1 expandidas pelo grafo.</li></ul><h3 id="_2-get-query-context-pack-l1-id" tabindex="-1">2. <code>GET /query/context_pack/:l1_id</code> <a class="header-anchor" href="#_2-get-query-context-pack-l1-id" aria-label="Permalink to &quot;2. `GET /query/context_pack/:l1_id`&quot;">​</a></h3><ul><li><strong>Logic</strong>: <ol><li>Recupera a abstração L1.</li><li>Busca chunks L0 no Postgres usando <code>chunk_index BETWEEN anchor - radius AND anchor + radius</code>.</li><li>Monta o Prompt de Sistema T5.</li></ol></li><li><strong>Return</strong>: String formatada para a LLM.</li></ul><h2 id="otimizacoes-rust" tabindex="-1">Otimizações Rust <a class="header-anchor" href="#otimizacoes-rust" aria-label="Permalink to &quot;Otimizações Rust&quot;">​</a></h2><ul><li><strong>PPR em SQL</strong>: Rodar o cálculo de score diretamente via CTEs recursivas no Postgres para evitar latência de rede.</li><li><strong>Async Streams</strong>: Retornar o Context Pack via stream para grandes volumes de código.</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li>Implementar <code>struct TopologyEngine</code> no <code>main.rs</code>.</li><li>Adicionar as rotas no <code>axum</code> (ou framework utilizado).</li></ul>',12)])])}const h=a(i,[["render",s]]);export{_ as __pageData,h as default};
